// 1. CARGAMOS LOS SONIDOS DIRECTAMENTE
const audioDado = new Audio('data:audio/mpeg;base64,');
const audioMoneda = new Audio('data:audio/mpeg;base64,');

// 2. FUNCIONES ÚNICAS DE SONIDO
function sonarDado() {
    audioDado.currentTime = 0;
    audioDado.play().catch(e => console.log("Haz clic en la página para sonar"));
}

function sonarMoneda() {
    audioMoneda.currentTime = 0;
    audioMoneda.play().catch(e => console.log("Haz clic en la página para sonar"));
}

// --- ESTADÍSTICAS (VIDA, RAPIDEZ, FUERZA, PODER, ATAQUE) ---
let puntosVida = 0;
function generarVida() { 
    puntosVida = Math.floor(Math.random() * 91) + 10; 
    actualizarPantalla(); 
}
function ajustarVida(op) { 
    let n = parseInt(prompt("¿Cantidad a " + op + "?", "0"));
    if (!isNaN(n)) { puntosVida = (op === 'sumar') ? puntosVida + n : puntosVida - n; actualizarPantalla(); }
}
function actualizarPantalla() { document.getElementById('valorVida').innerText = puntosVida; }

