// --- DADOS BÁSICOS (D4, D6, D8, D10) CON EFECTO ---
function lanzarBasico(id, max) {
    sonarDado();
    document.getElementById(id).innerText = Math.floor(Math.random() * max) + 1;
}

function lanzarD4() { lanzarBasico('valorD4', 4); }
function lanzarD6() { lanzarBasico('valorD6', 6); }
function lanzarD8() { lanzarBasico('valorD8', 8); }
function lanzarD10() { lanzarBasico('valorD10', 10); }

// --- DADOS GRANDES (D12, D20, D50, D100) CONECTADOS AL SONIDO ---
function lanzarD12() { lanzarBasico('valorD12', 12); }
function lanzarD20() { lanzarBasico('valorD20', 20); }
function lanzarD50() { lanzarBasico('valorD50', 50); }
function lanzarD100() { lanzarBasico('valorD100', 100); }

// --- CONEXIÓN PARA LA MONEDA ---
function lanzarMoneda() {
    sonarMoneda(); // Esto activa tu función de sonido de moneda
    let num = document.getElementById('valorMoneda');
    num.innerText = "...";
    setTimeout(() => {
        let opciones = ["CA", "CR"];
        num.innerText = opciones[Math.floor(Math.random() * 2)];
    }, 150);
}
// --- SISTEMA DE MÚSICA XYZ ---
const musicaFondo = new Audio('data:audio/mpeg;base64,');
musicaFondo.loop = true;
musicaFondo.volume = 0.15; 

function controlarMusica() {
    if (musicaFondo.paused) {
        musicaFondo.play().catch(e => {
            console.log("Para sonar la música, lanza un dado primero.");
        });
    } else {
        musicaFondo.pause();
    }
}
// Función para mostrar la carta elegida en el espacio index_30
function cambiarCartaLider(rutaImagen) {
    const cartaMostrada = document.getElementById('carta-mostrada');
    
    if (rutaImagen !== "") {
        cartaMostrada.src = rutaImagen;
        cartaMostrada.style.display = "block"; // Muestra la carta elegida
        console.log("Cambiado a: " + rutaImagen);
    } else {
        cartaMostrada.style.display = "none"; // Si no eliges nada, vuelve al negro
    }
}
// --- FUNCIONES PARA EL MENÚ DEL LÍDER ---

function toggleListaGenerica(idLista) {
    const lista = document.getElementById(idLista);
    if (window.event) window.event.stopPropagation();

    // Cerramos cualquier otra lista abierta para que no choquen
    const todasLasListas = ['mi-lista-cartas', 'mi-lista-1', 'mi-lista-2', 'mi-lista-3'];
    todasLasListas.forEach(id => {
        const otra = document.getElementById(id);
        if (otra && id !== idLista) otra.style.display = 'none';
    });

    if (lista.style.display === 'none' || lista.style.display === '') {
        lista.style.display = 'block';
    } else {
        lista.style.display = 'none';
    }
}

function cambiarCartaGenerica(idImagen, idLista, rutaImagen, nombre) {
    const cartaMostrada = document.getElementById(idImagen);
    const lista = document.getElementById(idLista);

    // 1. Cargamos la imagen
    cartaMostrada.src = rutaImagen;
    
    // 2. ASEGURAMOS EL TAMAÑO (Para que no se agrande sola)
    cartaMostrada.style.width = "100%";
    cartaMostrada.style.height = "100%";
    cartaMostrada.style.display = "block";

    // 3. CERRAMOS LA LISTA
    lista.style.display = "none";

    if (window.event) window.event.stopPropagation();
    console.log("Guerrero " + nombre + " posicionado en " + idImagen);
}